"use client";

import { useEffect, useRef, useState, type RefObject } from "react";

/** Backing-store resolution cap — a gradient field gains nothing above 2. */
const MAX_DPR = 2;
/** Pointer position lerp per 60fps-normalized frame. */
const POINTER_LERP = 0.07;
/** Energy attack / release — quick to notice you, slow to forget. */
const ENERGY_ATTACK = 0.05;
const ENERGY_RELEASE = 0.02;
/** After this much pointer silence, the sky drifts on its own (ms). */
const IDLE_MS = 3200;
/**
 * Page scroll progress is amplified for the shader: the sky reaches deep
 * night a third of the way down, while the CSS tokens take the whole page.
 */
const TEMP_GAIN = 3;
/** Reduced motion renders exactly one composed frame at this time (s). */
const STILL_TIME = 38;

const VERT = `
attribute vec2 a_pos;
void main() {
  gl_Position = vec4(a_pos, 0.0, 1.0);
}
`;

const FRAG = `
precision highp float;

uniform vec2 u_res;
uniform float u_time;
uniform vec2 u_pointer;
uniform float u_energy;
uniform float u_temp;

float hash(vec2 p) {
  return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}

float noise(vec2 p) {
  vec2 i = floor(p);
  vec2 f = fract(p);
  vec2 u = f * f * (3.0 - 2.0 * f);
  return mix(
    mix(hash(i), hash(i + vec2(1.0, 0.0)), u.x),
    mix(hash(i + vec2(0.0, 1.0)), hash(i + vec2(1.0, 1.0)), u.x),
    u.y
  );
}

float fbm(vec2 p) {
  float v = 0.0;
  float a = 0.5;
  for (int i = 0; i < 3; i++) {
    v += a * noise(p);
    p = p * 2.03 + vec2(1.7, 9.2);
    a *= 0.5;
  }
  return v;
}

void main() {
  vec2 uv = gl_FragCoord.xy / u_res;
  float aspect = u_res.x / u_res.y;
  vec2 q = vec2(uv.x * aspect, uv.y);

  // The pointer pushes the curtains: a capped gaussian displacement,
  // already lerped on the CPU so the warp arrives like weather, not a cursor.
  vec2 ptr = vec2(u_pointer.x * aspect, u_pointer.y);
  vec2 d = q - ptr;
  float fall = exp(-dot(d, d) * 4.5);
  q += normalize(d + 0.0001) * fall * 0.22 * u_energy;

  float t = u_time * 0.045;

  // Flow field: one fbm advects the domain of the next (domain warping).
  float flow = fbm(vec2(q.x * 1.1 + t * 0.6, q.y * 1.8 - t * 0.25));
  float rib = fbm(vec2(
    q.x * 2.4 + flow * 2.2 - t * 0.4,
    q.y * 0.9 + flow * 0.8 + t * 0.15
  ));

  // Sharpen the noise into curtains: ridged fbm, then a hard power.
  float rid = 1.0 - abs(rib * 2.0 - 1.0);
  rid = pow(rid, 2.6);

  // Curtains hang in the upper sky and die toward the horizon.
  float sky = smoothstep(0.06, 0.5, uv.y);
  // Fine vertical striation — the "rays" auroras are combed into.
  float ray = 0.72 + 0.28 * noise(vec2(q.x * 24.0 + flow * 3.0, t * 0.5));
  float glow = rid * (0.32 + 0.68 * flow) * sky * ray;
  // The sky leans toward your hand.
  glow *= 1.0 + fall * u_energy * 0.9;

  // Real curtains: green skirt low, magenta hem high.
  // u_temp shifts the weights — dusk leans magenta, deep night leans green.
  float hueMix = clamp(
    uv.y * 1.35 - 0.25 + (flow - 0.5) * 0.7 + (0.5 - u_temp) * 0.5,
    0.0, 1.0
  );
  vec3 green = vec3(0.435, 0.949, 0.765);
  vec3 magenta = vec3(0.761, 0.420, 0.949);
  vec3 aurora = mix(green, magenta, hueMix);

  vec3 night = vec3(0.055, 0.075, 0.188);
  vec3 deep = vec3(0.030, 0.045, 0.130);
  vec3 bg = mix(night, deep, u_temp);

  // Stars: stable hashed cells, each twinkling at its own rate,
  // swallowed where the curtain burns.
  vec2 sp = vec2(q.x, uv.y) * 90.0;
  float s = hash(floor(sp));
  float star = step(0.994, s) * max(0.0, 1.0 - length(fract(sp) - 0.5) * 4.0);
  star *= 0.35 + 0.65 * (0.5 + 0.5 * sin(u_time * (0.5 + s) + s * 80.0));
  star *= smoothstep(0.3, 0.75, uv.y) * (1.0 - min(glow * 2.2, 1.0));

  vec3 col = bg + aurora * glow + vec3(0.87, 0.91, 1.0) * star * 0.55;
  // A faint horizon breath in the ridge-line blue.
  col += vec3(0.153, 0.251, 0.420) * exp(-uv.y * 8.0) * 0.4;

  // Ordered-ish dither: kills gradient banding on dark displays.
  col += (hash(gl_FragCoord.xy + u_time) - 0.5) * 0.006;

  gl_FragColor = vec4(col, 1.0);
}
`;

type Props = {
  /** The hero section — pointer events and sizing come from it. */
  stageRef: RefObject<HTMLElement | null>;
  reduced: boolean;
  paused: boolean;
};

/**
 * The aurora itself: a hand-rolled WebGL fragment shader (no libraries) on a
 * DPR-capped canvas. Layer order is the fallback plan — the CSS gradient
 * aurora is always painted underneath, and the canvas fades in over it only
 * after a first frame actually lands. No WebGL, a failed compile, or a lost
 * context all resolve to the same thing: the CSS sky, never a black hole.
 *
 * The rAF loop pauses when the hero leaves the viewport (IO), when the tab
 * hides (visibilitychange), and when the visitor presses "pause the sky".
 * Reduced motion draws exactly one composed frame and never starts the loop.
 */
export default function AuroraCanvas({ stageRef, reduced, paused }: Props) {
  const wrapRef = useRef<HTMLDivElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const [fallback, setFallback] = useState(false);
  const pausedRef = useRef(paused);
  const syncRef = useRef<(() => void) | null>(null);

  // The pause button must not rebuild the GL context — it only pokes sync().
  useEffect(() => {
    pausedRef.current = paused;
    syncRef.current?.();
  }, [paused]);

  useEffect(() => {
    if (fallback) return;
    const canvas = canvasRef.current;
    const stage = stageRef.current;
    const wrap = wrapRef.current;
    if (!canvas || !stage || !wrap) return;

    const gl = canvas.getContext("webgl", {
      alpha: false,
      antialias: false,
      depth: false,
      stencil: false,
      powerPreference: "low-power",
    });
    if (!gl) {
      setFallback(true);
      return;
    }

    const bail = () => {
      gl.getExtension("WEBGL_lose_context")?.loseContext();
      setFallback(true);
    };

    const compile = (type: number, src: string): WebGLShader | null => {
      const sh = gl.createShader(type);
      if (!sh) return null;
      gl.shaderSource(sh, src);
      gl.compileShader(sh);
      if (!gl.getShaderParameter(sh, gl.COMPILE_STATUS)) {
        gl.deleteShader(sh);
        return null;
      }
      return sh;
    };

    const vs = compile(gl.VERTEX_SHADER, VERT);
    const fs = compile(gl.FRAGMENT_SHADER, FRAG);
    const prog = gl.createProgram();
    if (!vs || !fs || !prog) {
      bail();
      return;
    }
    gl.attachShader(prog, vs);
    gl.attachShader(prog, fs);
    gl.linkProgram(prog);
    if (!gl.getProgramParameter(prog, gl.LINK_STATUS)) {
      bail();
      return;
    }
    gl.useProgram(prog);

    // One oversized triangle beats a quad: no diagonal seam, one draw call.
    gl.bindBuffer(gl.ARRAY_BUFFER, gl.createBuffer());
    gl.bufferData(
      gl.ARRAY_BUFFER,
      new Float32Array([-1, -1, 3, -1, -1, 3]),
      gl.STATIC_DRAW,
    );
    const aPos = gl.getAttribLocation(prog, "a_pos");
    gl.enableVertexAttribArray(aPos);
    gl.vertexAttribPointer(aPos, 2, gl.FLOAT, false, 0, 0);

    const uRes = gl.getUniformLocation(prog, "u_res");
    const uTime = gl.getUniformLocation(prog, "u_time");
    const uPointer = gl.getUniformLocation(prog, "u_pointer");
    const uEnergy = gl.getUniformLocation(prog, "u_energy");
    const uTemp = gl.getUniformLocation(prog, "u_temp");

    let raf = 0;
    let running = false;
    let visible = true;
    let disposed = false;
    let last = 0;
    let time = reduced ? STILL_TIME : 0;

    const ptr = { x: 0.5, y: 0.62, e: reduced ? 0.55 : 0 };
    let target = { x: 0.5, y: 0.62, e: 0 };
    let lastMove = -1e9;

    const temp = () => {
      const max = Math.max(
        1,
        document.documentElement.scrollHeight - window.innerHeight,
      );
      return Math.min(1, (window.scrollY / max) * TEMP_GAIN);
    };

    const resize = () => {
      const rect = stage.getBoundingClientRect();
      const dpr = Math.min(window.devicePixelRatio || 1, MAX_DPR);
      canvas.width = Math.max(1, Math.round(rect.width * dpr));
      canvas.height = Math.max(1, Math.round(rect.height * dpr));
      gl.viewport(0, 0, canvas.width, canvas.height);
    };

    const draw = () => {
      gl.uniform2f(uRes, canvas.width, canvas.height);
      gl.uniform1f(uTime, time);
      gl.uniform2f(uPointer, ptr.x, ptr.y);
      gl.uniform1f(uEnergy, ptr.e);
      gl.uniform1f(uTemp, temp());
      gl.drawArrays(gl.TRIANGLES, 0, 3);
    };

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const dt = Math.min(now - last, 50);
      last = now;
      time += dt / 1000;

      // Touch, or an idle pointer: the sky scans on its own (slow lissajous).
      if (now - lastMove > IDLE_MS) {
        target = {
          x: 0.5 + 0.3 * Math.sin(time * 0.13),
          y: 0.6 + 0.18 * Math.sin(time * 0.21 + 1.7),
          e: 0.55 + 0.18 * Math.sin(time * 0.29),
        };
      }
      const k = dt / 16.7; // frame-rate normalization
      ptr.x += (target.x - ptr.x) * POINTER_LERP * k;
      ptr.y += (target.y - ptr.y) * POINTER_LERP * k;
      const ek = target.e > ptr.e ? ENERGY_ATTACK : ENERGY_RELEASE;
      ptr.e += (target.e - ptr.e) * ek * k;

      draw();
    };

    const shouldRun = () =>
      !reduced && !pausedRef.current && visible && !document.hidden;

    const sync = () => {
      if (disposed) return;
      if (shouldRun()) {
        if (!running) {
          running = true;
          last = performance.now();
          raf = requestAnimationFrame(step);
        }
      } else if (running) {
        running = false;
        cancelAnimationFrame(raf);
      }
    };
    syncRef.current = sync;

    const onPointerMove = (ev: PointerEvent) => {
      const rect = stage.getBoundingClientRect();
      target = {
        x: (ev.clientX - rect.left) / rect.width,
        y: 1 - (ev.clientY - rect.top) / rect.height, // GL is y-up
        e: 1,
      };
      lastMove = performance.now();
    };
    const onPointerLeave = () => {
      lastMove = -1e9;
    };
    const onVisibility = () => sync();
    const onContextLost = () => {
      // Do not restore — hand the sky to the CSS fallback underneath.
      running = false;
      cancelAnimationFrame(raf);
      setFallback(true);
    };

    resize();
    draw(); // first frame now — also the one still frame under reduced motion
    wrap.classList.add("is-live");

    if (!reduced) {
      stage.addEventListener("pointermove", onPointerMove, { passive: true });
      stage.addEventListener("pointerleave", onPointerLeave);
    }
    canvas.addEventListener("webglcontextlost", onContextLost);
    document.addEventListener("visibilitychange", onVisibility);

    const io = new IntersectionObserver(
      (hits) => {
        visible = hits[hits.length - 1].isIntersecting;
        sync();
      },
      { rootMargin: "80px 0px" },
    );
    io.observe(stage);

    const ro = new ResizeObserver(() => {
      resize();
      if (!running) draw();
    });
    ro.observe(stage);

    sync();

    return () => {
      disposed = true;
      syncRef.current = null;
      running = false;
      cancelAnimationFrame(raf);
      io.disconnect();
      ro.disconnect();
      stage.removeEventListener("pointermove", onPointerMove);
      stage.removeEventListener("pointerleave", onPointerLeave);
      canvas.removeEventListener("webglcontextlost", onContextLost);
      document.removeEventListener("visibilitychange", onVisibility);
      wrap.classList.remove("is-live");
      gl.getExtension("WEBGL_lose_context")?.loseContext();
    };
  }, [stageRef, reduced, fallback]);

  return (
    <div
      ref={wrapRef}
      className={`lumen-aurora${paused ? " is-paused" : ""}`}
      aria-hidden="true"
    >
      {/* Always painted: the CSS aurora is the no-JS view, the no-WebGL view,
          and the safety net under the canvas. */}
      <div className="lumen-aurora__fallback" />
      {!fallback && <canvas ref={canvasRef} className="lumen-aurora__canvas" />}
    </div>
  );
}

"use client";

/** Predicted intensity, hour by hour. The peak sits just after midnight. */
const DATA = [
  { h: "21", kp: 1.8 },
  { h: "22", kp: 3.1 },
  { h: "23", kp: 5.2 },
  { h: "00", kp: 5.7 },
  { h: "01", kp: 4.6 },
  { h: "02", kp: 3.0 },
  { h: "03", kp: 2.2 },
] as const;

const W = 640;
const H = 190;
const PAD_X = 26;
const BASE_Y = 148;
const KP_SCALE = 17; // px per Kp
const STORM_Y = BASE_Y - 5 * KP_SCALE; // the Kp 5 storm threshold

const px = (i: number) => PAD_X + (i * (W - PAD_X * 2)) / (DATA.length - 1);
const py = (kp: number) => BASE_Y - kp * KP_SCALE;

type Pt = { x: number; y: number };

/** Catmull-Rom through the readings, emitted as cubic beziers. */
function smoothPath(p: Pt[]): string {
  let d = `M ${p[0].x.toFixed(1)} ${p[0].y.toFixed(1)}`;
  for (let i = 0; i < p.length - 1; i++) {
    const p0 = p[Math.max(0, i - 1)];
    const p1 = p[i];
    const p2 = p[i + 1];
    const p3 = p[Math.min(p.length - 1, i + 2)];
    const c1x = p1.x + (p2.x - p0.x) / 6;
    const c1y = p1.y + (p2.y - p0.y) / 6;
    const c2x = p2.x - (p3.x - p1.x) / 6;
    const c2y = p2.y - (p3.y - p1.y) / 6;
    d += ` C ${c1x.toFixed(1)} ${c1y.toFixed(1)}, ${c2x.toFixed(1)} ${c2y.toFixed(1)}, ${p2.x.toFixed(1)} ${p2.y.toFixed(1)}`;
  }
  return d;
}

const PTS: Pt[] = DATA.map((d, i) => ({ x: px(i), y: py(d.kp) }));
const LINE = smoothPath(PTS);
const AREA = `${LINE} L ${PTS[PTS.length - 1].x.toFixed(1)} ${BASE_Y} L ${PTS[0].x.toFixed(1)} ${BASE_Y} Z`;

/**
 * Section 03 — the forecast log. The night's predicted intensity as a
 * sparkline that draws itself on scroll-into-view (pathLength-normalized
 * stroke-dashoffset, triggered by the shared reveal observer), followed by
 * three lines on how the bureau listens. Without JS, or under reduced
 * motion, the line is simply there — fully drawn.
 */
export default function ForecastLog() {
  return (
    <section className="lumen-log" aria-labelledby="lumen-log-title">
      <div className="lumen-section__head" data-reveal>
        <p className="lumen-section__no" aria-hidden="true">
          03
        </p>
        <h2 className="lumen-section__title" id="lumen-log-title">
          The night, hour by hour{" "}
          <span lang="ko" className="lumen-section__ko">
            시간별 예측
          </span>
        </h2>
        <p className="lumen-section__meta">
          PREDICTED INTENSITY · <span lang="ko">예측 강도</span>
        </p>
      </div>

      <div className="lumen-spark" data-reveal>
        <svg
          className="lumen-spark__svg"
          viewBox={`0 0 ${W} ${H}`}
          role="img"
          aria-label="Forecast sparkline: activity rises from Kp 1.8 at 21:00 to a peak of Kp 5.7 around midnight, crossing the storm threshold between 23:00 and 01:00, then eases to Kp 2.2 by 03:00. 예측 그래프: 활동은 21시 Kp 1.8에서 자정 무렵 최고치 Kp 5.7까지 올라 23시부터 01시 사이 폭풍 문턱을 넘고, 03시에는 Kp 2.2로 잦아든다."
        >
          <defs>
            <linearGradient id="lumen-spark-grad" x1="0" y1="0" x2="1" y2="0">
              <stop offset="0" className="lumen-spark__stop-a" />
              <stop offset="1" className="lumen-spark__stop-b" />
            </linearGradient>
            <linearGradient id="lumen-spark-fill" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0" className="lumen-spark__stop-fill" />
              <stop offset="1" className="lumen-spark__stop-none" />
            </linearGradient>
          </defs>

          <line
            className="lumen-spark__threshold"
            x1={PAD_X}
            y1={STORM_Y}
            x2={W - PAD_X}
            y2={STORM_Y}
          />
          <text
            className="lumen-spark__note"
            x={PAD_X}
            y={STORM_Y - 8}
          >
            Kp 5 — storm threshold · 폭풍 문턱
          </text>

          <path className="lumen-spark__area" d={AREA} />
          <path className="lumen-spark__line" d={LINE} pathLength={1} />

          {DATA.map((d, i) => (
            <g key={d.h}>
              <circle
                className="lumen-spark__dot"
                cx={px(i)}
                cy={py(d.kp)}
                r={3.2}
                style={{ transitionDelay: `${1100 + i * 110}ms` }}
              />
              <text
                className="lumen-spark__label"
                x={px(i)}
                y={H - 10}
                textAnchor="middle"
              >
                {d.h}
              </text>
            </g>
          ))}
        </svg>
        <p className="lumen-spark__caption">
          Hours in KST. The sky keeps its own schedule; this is our best
          argument with it.{" "}
          <span lang="ko">
            시각은 KST. 하늘은 제 일정대로 움직인다 — 이것은 우리가 하늘과
            벌이는 가장 정중한 논쟁이다.
          </span>
        </p>
      </div>

      <div className="lumen-method" data-reveal>
        <h3 className="lumen-method__title">
          How the bureau listens{" "}
          <span lang="ko" className="lumen-section__ko">
            예보국이 듣는 법
          </span>
        </h3>
        <ul className="lumen-method__list">
          <li>
            We read the solar wind ninety minutes before it arrives.
            <span lang="ko" className="lumen-method__ko">
              태양풍이 도착하기 구십 분 전에, 우리가 먼저 읽는다.
            </span>
          </li>
          <li>
            Three magnetometers hold their breath in the dark.
            <span lang="ko" className="lumen-method__ko">
              자력계 세 대가 어둠 속에서 숨을 참는다.
            </span>
          </li>
          <li>
            Cameras pointed at nothing, all night, on purpose.
            <span lang="ko" className="lumen-method__ko">
              카메라들은 일부러, 밤새, 아무것도 없는 곳을 본다.
            </span>
          </li>
        </ul>
      </div>
    </section>
  );
}

"use client";

import {
  useCallback,
  useRef,
  type PointerEvent as ReactPointerEvent,
  type ReactNode,
} from "react";

type Props = {
  className?: string;
  children: ReactNode;
};

/**
 * The specular glass primitive. A backdrop-filter panel whose highlight — a
 * radial gradient on the ::spec layer — tracks the pointer through two custom
 * properties written straight to the element (no React state, no re-render
 * per move). With no pointer (touch, keyboard, SSR) the highlight rests at
 * its default position near the top center, at reduced strength: the panel
 * still reads as lit glass, it just is not following anyone.
 */
export default function GlassPanel({ className, children }: Props) {
  const ref = useRef<HTMLDivElement | null>(null);

  const onPointerMove = useCallback(
    (ev: ReactPointerEvent<HTMLDivElement>) => {
      const el = ref.current;
      if (!el) return;
      const r = el.getBoundingClientRect();
      const x = ((ev.clientX - r.left) / r.width) * 100;
      const y = ((ev.clientY - r.top) / r.height) * 100;
      el.style.setProperty("--lumen-gx", `${x.toFixed(2)}%`);
      el.style.setProperty("--lumen-gy", `${y.toFixed(2)}%`);
      el.style.setProperty("--lumen-gs", "1");
    },
    [],
  );

  const onPointerLeave = useCallback(() => {
    const el = ref.current;
    if (!el) return;
    el.style.removeProperty("--lumen-gx");
    el.style.removeProperty("--lumen-gy");
    el.style.removeProperty("--lumen-gs");
  }, []);

  return (
    <div
      ref={ref}
      className={`lumen-glass${className ? ` ${className}` : ""}`}
      onPointerMove={onPointerMove}
      onPointerLeave={onPointerLeave}
    >
      <div className="lumen-glass__spec" aria-hidden="true" />
      <div className="lumen-glass__body">{children}</div>
    </div>
  );
}

"use client";

import { useRef, useState } from "react";
import AuroraCanvas from "./AuroraCanvas";

type Props = {
  reduced: boolean;
};

/**
 * Section 01 — the sky itself. A full-viewport WebGL aurora (with a CSS
 * gradient understudy) behind the bureau's masthead and tonight's headline
 * probability. The pause button satisfies WCAG 2.2.2 for the ambient shader;
 * it is display-gated behind `.lumen-js` and hidden under reduced motion,
 * where there is nothing left to pause.
 */
export default function Hero({ reduced }: Props) {
  const stageRef = useRef<HTMLElement | null>(null);
  const [paused, setPaused] = useState(false);

  return (
    <header ref={stageRef} className="lumen-hero" aria-label="LUMEN NORD">
      <AuroraCanvas stageRef={stageRef} reduced={reduced} paused={paused} />
      <div className="lumen-hero__scrim" aria-hidden="true" />

      <div className="lumen-hero__inner">
        <p className="lumen-kicker">
          NIGHTLY AURORA FORECAST ·{" "}
          <span lang="ko" className="lumen-kicker__ko">
            야간 오로라 예보
          </span>
        </p>

        <h1 className="lumen-title">
          LUMEN NORD
          <span lang="ko" className="lumen-title__ko">
            오로라 예보국
          </span>
        </h1>

        <p className="lumen-lede">
          TONIGHT — 78% chance the sky remembers it is a curtain.
          <span lang="ko" className="lumen-lede__ko">
            오늘 밤, 하늘은 자신이 커튼이었음을 기억할 확률 78%.
          </span>
        </p>

        <p className="lumen-issue">
          BULLETIN NO. 2189 · ISSUED 21:00 KST / 13:00 CET · NORDFJELL RIDGE
          69.3°N
        </p>

        <p className="lumen-hero__hint" aria-hidden="true">
