"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, type RefObject } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. The pre-reveal state (opacity/translate)
 * lives in styles.css and is gated behind the `.lumen-js` root class, so the
 * content is fully visible when JavaScript never runs.
 *
 * The forecast sparkline piggybacks on the same class: its
 * stroke-dashoffset draw is triggered by `.is-visible` on its wrapper.
 *
 * Elements that intersect in the same observer batch are staggered 80ms
 * apart via transition-delay, so a screenful never fades as one slab.
 */
export function useReveal(
  rootRef: RefObject<HTMLElement | null>,
  disabled: boolean,
): void {
  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          el.style.transitionDelay = `${batch * 80}ms`;
          el.classList.add("is-visible");
          io.unobserve(el);
          batch += 1;
        }
      },
      { threshold: 0.15, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [rootRef, disabled]);
}

"use client";

import { useEffect, type RefObject } from "react";

/** Aurora green — where the page ends (deep night). */
const GREEN: readonly [number, number, number] = [111, 242, 195];
/** Magenta veil — where the page begins (dusk). */
const MAGENTA: readonly [number, number, number] = [194, 107, 242];

function lerpChannel(a: number, b: number, t: number): number {
  return Math.round(a + (b - a) * t);
}

/**
 * Drives the page's color temperature from scroll progress.
 *
 * Writes three custom properties on the entry root, rAF-throttled from a
 * passive scroll listener:
 *   --lumen-temp        raw 0→1 progress (0 = dusk at the top, 1 = deep night)
 *   --lumen-blend       magenta→green interpolated accent, as rgb()
 *   --lumen-blend-soft  the same hue at 35% alpha, for borders and edges
 *
 * The aurora shader reads the same scroll position on the GPU side
 * (amplified — see AuroraCanvas.TEMP_GAIN), so canvas and CSS agree on what
 * time of night it is. This is direct input→style manipulation, not an
 * autonomous animation, so it stays live under prefers-reduced-motion.
 */
export function useScrollTemperature(
  rootRef: RefObject<HTMLElement | null>,
): void {
  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;

    let raf = 0;

    const apply = () => {
      raf = 0;
      const doc = document.documentElement;
      const max = Math.max(1, doc.scrollHeight - window.innerHeight);
      const t = Math.min(1, Math.max(0, window.scrollY / max));
      const r = lerpChannel(MAGENTA[0], GREEN[0], t);
      const g = lerpChannel(MAGENTA[1], GREEN[1], t);
      const b = lerpChannel(MAGENTA[2], GREEN[2], t);
      root.style.setProperty("--lumen-temp", t.toFixed(4));
      root.style.setProperty("--lumen-blend", `rgb(${r} ${g} ${b})`);
      root.style.setProperty(
        "--lumen-blend-soft",
        `rgb(${r} ${g} ${b} / 0.35)`,
      );
    };

    const schedule = () => {
      if (!raf) raf = requestAnimationFrame(apply);
    };

    apply();
    window.addEventListener("scroll", schedule, { passive: true });
    window.addEventListener("resize", schedule, { passive: true });
    return () => {
      window.removeEventListener("scroll", schedule);
      window.removeEventListener("resize", schedule);
      if (raf) cancelAnimationFrame(raf);
    };
  }, [rootRef]);
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { hahmlet, sora } from "./fonts";
import Hero from "./components/Hero";
import BulletinPanels from "./components/BulletinPanels";
import ForecastLog from "./components/ForecastLog";
import Footer from "./components/Footer";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";
import { useScrollTemperature } from "./hooks/useScrollTemperature";

/**
 * LUMEN NORD — aurora forecast bureau.
 * A fictional Nordic–Korean joint observatory that issues nightly aurora
 * forecasts the way other agencies issue weather: Kp readings, visibility
 * windows, and one poetic advisory per bulletin. Hahmlet speaks for the sky,
 * Sora for the instruments; a pointer-warped WebGL aurora carries the light.
 *
 * `.lumen-js` is added on mount so every scroll-reveal style is JS-gated —
 * with JavaScript disabled the full bulletin is simply readable, over the
 * CSS-gradient aurora that also serves as the WebGL fallback.
 */
export default function LumenNordPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  useReveal(rootRef, reduced);
  useScrollTemperature(rootRef);

  useEffect(() => {
    // Imperative on purpose: the class is a signal to CSS that JS is alive,
    // not React state — and it never changes once set.
    rootRef.current?.classList.add("lumen-js");
    window.parent?.postMessage(
      { type: "oneshot:ready", slug: "lumen-nord" },
      "*",
    );
  }, []);

  return (
    <div
      id="lumen-top"
      ref={rootRef}
      className={`${hahmlet.variable} ${sora.variable} lumen-root`}
    >
      <Hero reduced={reduced} />
      <main>
        <BulletinPanels />
        <ForecastLog />
      </main>
      <Footer />
    </div>
  );
}

/* ==========================================================================
   LUMEN NORD — aurora forecast bureau
   glass-futurism · polar night, aurora green, magenta veil · every color a token
   Scoped by convention to .lumen-root; classes prefixed lumen-.
   ========================================================================== */

/* Registered so the specular strength can ease in and out; where @property
   is unsupported the highlight simply snaps — a harmless degrade. */
@property --lumen-gs {
  syntax: "<number>";
  inherits: true;
  initial-value: 0.55;
}

.lumen-root {
  /* -- palette ---------------------------------------------------------- */
  --lumen-night: #0e1330;         /* polar night — the ground everything stands on */
  --lumen-deep: #080b20;          /* derived: where the night goes when you scroll */
  --lumen-green: #6ff2c3;         /* aurora green — accent, focus, the skirt of the curtain (13.1:1) */
  --lumen-magenta: #c26bf2;       /* magenta veil — the hem, the dusk end of the blend (5.8:1) */
  --lumen-ice: #dfe9ff;           /* primary text (14.9:1 on night) */
  --lumen-ice-dim: rgba(223, 233, 255, 0.72); /* ≈ #a4adc5 — secondary text (8.1:1) */
  --lumen-horizon: #27406b;       /* decorative ONLY (1.9:1): rules, ridge glow */
  --lumen-hairline: rgba(39, 64, 107, 0.55);  /* derived from horizon */
  --lumen-glass-fill: rgba(18, 24, 56, 0.58); /* glass panel body over the afterglow */

  /* -- scroll temperature (JS lerps these; the statics are the dusk state) */
  --lumen-temp: 0;
  --lumen-blend: rgb(194 107 242);
  --lumen-blend-soft: rgb(194 107 242 / 0.35);

  /* -- type -------------------------------------------------------------- */
  --lumen-font-display: var(--font-hahmlet), "Hahmlet", georgia, serif;
  /* Hangul falls through Sora into Hahmlet: Korean body text is serif on purpose */
  --lumen-font-body: var(--font-sora), var(--font-hahmlet), sans-serif;

  /* -- motion ------------------------------------------------------------ */
  --lumen-ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  --lumen-reveal-ms: 700ms;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--lumen-night);
  /* Deepens as you scroll — supported browsers only; the line above is the floor. */
  background: color-mix(
    in srgb,
    var(--lumen-night),
    var(--lumen-deep) calc(var(--lumen-temp) * 100%)
  );
  color: var(--lumen-ice);
  font-family: var(--lumen-font-body);
  font-size: clamp(15px, 0.35vw + 13.5px, 17px);
  line-height: 1.65;
  overflow-x: hidden;
  overflow-x: clip;
}

/* Korean is first-class: it lands in Hahmlet through the stack, keeps its
   own line-breaking rules, and is never letter-spaced apart. */
.lumen-root :lang(ko) {
