  display: block;
  width: min(210px, 70%);
  margin: 0.7rem 0 0.1rem;
}

.lumen-gauge__track {
  fill: none;
  stroke: rgba(223, 233, 255, 0.14);
  stroke-width: 7;
  stroke-linecap: round;
}

.lumen-gauge__fill {
  fill: none;
  stroke: var(--lumen-green);
  stroke-width: 7;
  stroke-linecap: round;
  filter: drop-shadow(0 0 6px rgba(111, 242, 195, 0.5));
}

/* -- the visibility window bar --------------------------------------------- */

.lumen-window {
  position: relative;
  height: 32px;
  margin: 0.9rem 0 1.5rem;
  border-bottom: 1px solid rgba(223, 233, 255, 0.2);
}

.lumen-window__band {
  position: absolute;
  top: 7px;
  bottom: 7px;
  left: 27.8%; /* 22:40 on a 21:00–03:00 track */
  width: 41.7%; /* through 01:10 */
  border-radius: 6px;
  background: linear-gradient(
    90deg,
    rgba(111, 242, 195, 0.55),
    rgba(194, 107, 242, 0.5)
  );
  box-shadow: 0 0 16px rgba(111, 242, 195, 0.3);
}

.lumen-window__tick {
  position: absolute;
  top: 4px;
  bottom: 0;
  left: 0;
  width: 1px;
  background: rgba(223, 233, 255, 0.28);
}

.lumen-window__tick::after {
  content: attr(data-hour);
  position: absolute;
  top: calc(100% + 3px);
  left: 0;
  font-size: 0.62rem;
  letter-spacing: 0.08em;
  color: var(--lumen-ice-dim);
  white-space: nowrap;
}

.lumen-window__tick--mid {
  left: 50%;
}

.lumen-window__tick--mid::after {
  left: 50%;
  transform: translateX(-50%);
}

.lumen-window__tick--end {
  left: auto;
  right: 0;
}

.lumen-window__tick--end::after {
  left: auto;
  right: 0;
}

/* ==========================================================================
   03 · The forecast log — sparkline + how the bureau listens
   ========================================================================== */

.lumen-log {
  max-width: 1020px;
  margin-inline: auto;
  padding: clamp(80px, 12vh, 150px) clamp(20px, 5vw, 64px);
}

.lumen-spark__svg {
  display: block;
  width: 100%;
  height: auto;
}

.lumen-spark__threshold {
  stroke: rgba(223, 233, 255, 0.18);
  stroke-dasharray: 5 7;
}

.lumen-spark__note,
.lumen-spark__label {
  fill: var(--lumen-ice-dim);
  font-family: var(--lumen-font-body);
  font-size: 11px;
  letter-spacing: 0.06em;
}

.lumen-spark__label {
  font-size: 12px;
}

.lumen-spark__line {
  fill: none;
  stroke: url(#lumen-spark-grad);
  stroke-width: 2.5;
  stroke-linecap: round;
}

.lumen-spark__area {
  fill: url(#lumen-spark-fill);
}

.lumen-spark__dot {
  fill: var(--lumen-night);
  stroke: var(--lumen-green);
  stroke-width: 2;
}

.lumen-spark__stop-a {
  stop-color: var(--lumen-green);
}

.lumen-spark__stop-b {
  stop-color: var(--lumen-magenta);
}

.lumen-spark__stop-fill {
  stop-color: rgba(111, 242, 195, 0.16);
}

.lumen-spark__stop-none {
  stop-color: rgba(111, 242, 195, 0);
}

.lumen-spark__caption {
  margin: 1.1rem 0 0;
  font-size: 0.85rem;
  color: var(--lumen-ice-dim);
  max-width: 70ch;
}

/* The draw: pathLength is normalized to 1 in the markup, so one dash unit
   covers the whole line. Pre-states are JS-gated — no JS, no hidden line. */
.lumen-js .lumen-spark__line {
  stroke-dasharray: 1 1;
  stroke-dashoffset: 1;
}

.lumen-js .lumen-spark__area,
.lumen-js .lumen-spark__dot {
  opacity: 0;
}

.lumen-js .lumen-spark.is-visible .lumen-spark__line {
  stroke-dashoffset: 0;
  transition: stroke-dashoffset 1900ms cubic-bezier(0.33, 0, 0.2, 1) 200ms;
}

.lumen-js .lumen-spark.is-visible .lumen-spark__area {
  opacity: 1;
  transition: opacity 900ms ease 1500ms;
}

.lumen-js .lumen-spark.is-visible .lumen-spark__dot {
  opacity: 1;
  transition: opacity 500ms ease; /* per-dot delay set inline */
}

/* -- how the bureau listens ------------------------------------------------ */

.lumen-method {
  margin-top: clamp(3rem, 7vh, 5rem);
  padding-top: 2.2rem;
  border-top: 1px solid var(--lumen-hairline);
}

.lumen-method__title {
  margin: 0;
  font-family: var(--lumen-font-display);
  font-weight: 500;
  font-size: clamp(1.2rem, 2.2vw, 1.55rem);
}

.lumen-method__list {
  list-style: none;
  margin: 1.5rem 0 0;
  padding: 0;
  display: grid;
  gap: 1.35rem;
}

.lumen-method__list li {
  padding-left: 1.2rem;
  border-left: 2px solid var(--lumen-blend-soft);
  font-family: var(--lumen-font-display);
}

.lumen-method__ko {
  display: block;
  margin-top: 0.25rem;
  color: var(--lumen-ice-dim);
}

/* ==========================================================================
   04 · Footer — end of watch
   ========================================================================== */

.lumen-footer {
  max-width: 1020px;
  margin-inline: auto;
  padding: clamp(64px, 10vh, 120px) clamp(20px, 5vw, 64px)
    clamp(90px, 13vh, 150px);
  border-top: 1px solid var(--lumen-hairline);
}

.lumen-footer__signoff {
  margin: 0 0 2.2rem;
  font-family: var(--lumen-font-display);
  font-size: clamp(1.1rem, 2vw, 1.45rem);
  line-height: 1.5;
}

.lumen-footer__ko {
  display: block;
  margin-top: 0.35rem;
  color: var(--lumen-ice-dim);
}

.lumen-footer__data {
  margin: 0 0 2.4rem;
}

.lumen-footer__data div {
  display: flex;
  flex-wrap: wrap;
  gap: 0.2rem 1.2rem;
  padding: 0.55rem 0;
  border-bottom: 1px dotted var(--lumen-hairline);
}

.lumen-footer__data dt {
  flex: 0 0 6.5rem;
  font-size: 0.68rem;
  font-weight: 600;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--lumen-ice-dim);
  line-height: 2.1;
}

.lumen-footer__data dd {
  flex: 1 1 16rem;
  margin: 0;
}

.lumen-footer__nav {
  margin: 0 0 2.4rem;
  font-size: 0.9rem;
}

.lumen-footer__copy {
  margin: 0;
  font-size: 0.9rem;
}

/* ==========================================================================
   Scroll reveals — JS-gated pre-state, transform/opacity only
   ========================================================================== */

.lumen-js [data-reveal] {
  opacity: 0;
  transform: translateY(18px);
  transition:
    opacity var(--lumen-reveal-ms) var(--lumen-ease-out),
    transform var(--lumen-reveal-ms) var(--lumen-ease-out);
  will-change: opacity, transform;
}

.lumen-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* ==========================================================================
   Keyframes — transform only; the CSS aurora breathes, slowly
   ========================================================================== */

@keyframes lumen-drift {
  0% {
    transform: translate3d(-2%, 0.5%, 0) scale(1.05) rotate(-1.2deg);
  }
  50% {
    transform: translate3d(2%, -1.5%, 0) scale(1.12) rotate(1.3deg);
  }
  100% {
    transform: translate3d(-1%, 1%, 0) scale(1.07) rotate(-0.5deg);
  }
}

@keyframes lumen-sway {
  0% {
    transform: translate3d(-3%, 0, 0);
  }
  100% {
    transform: translate3d(3%, 0, 0);
  }
}

/* ==========================================================================
   Reduced motion — one composed still, everything readable
   (The WebGL loop is separately stopped in JS; this handles the CSS side.)
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .lumen-aurora__fallback,
  .lumen-aurora__fallback::after {
    animation: none;
  }

  .lumen-aurora__canvas,
  .lumen-glass {
    transition: none;
  }

  .lumen-js [data-reveal] {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .lumen-js .lumen-spark__line {
    stroke-dasharray: none;
    stroke-dashoffset: 0;
    transition: none;
  }

  .lumen-js .lumen-spark__area,
  .lumen-js .lumen-spark__dot {
    opacity: 1;
    transition: none;
  }

  /* The sky is already still — there is nothing to pause. */
  .lumen-js .lumen-skybtn {
    display: none;
  }
}
